module binary_subtractor(
    input [3:0] a,
    input [3:0] b,
    output [3:0] diff,
    output borrow_out
    );

    wire [3:0] carry_in;

    assign carry_in[0] = (~a[0] & b[0]);
    assign diff[0] = a[0] ^ b[0];

    assign carry_in[1] = (~a[1] & b[1]) | (~a[1] & carry_in[0]) | (b[1] & carry_in[0]);
    assign diff[1] = a[1] ^ b[1] ^ carry_in[0];

    assign carry_in[2] = (~a[2] & b[2]) | (~a[2] & carry_in[1]) | (b[2] & carry_in[1]);
    assign diff[2] = a[2] ^ b[2] ^ carry_in[1];

    assign carry_in[3] = (~a[3] & b[3]) | (~a[3] & carry_in[2]) | (b[3] & carry_in[2]);
    assign diff[3] = a[3] ^ b[3] ^ carry_in[2];

    assign borrow_out = carry_in[3];
endmodule
